import React from 'react';

function MovieDetails({ data }) {
    if (!data) return null;

    const castDetailed = data.cast_detailed || [];

    return (
        <div className="movie-details-hero">
            {/* Backdrop */}
            <div className="hero-backdrop">
                <img src={data.backdrop} alt={data.title} />
                <div className="hero-overlay" />
            </div>

            {/* Content */}
            <div className="hero-content">
                <div className="hero-layout">
                    {/* Poster */}
                    <div className="hero-poster-wrap">
                        <img
                            src={data.poster}
                            alt={data.title}
                            className="hero-poster"
                        />
                    </div>

                    {/* Info */}
                    <div className="hero-info">
                        <h1 className="hero-title">{data.title}</h1>

                        <div className="hero-meta">
                            {data.year && data.year !== '—' && (
                                <span className="meta-tag">{data.year}</span>
                            )}
                            {data.genres && data.genres.map((g, i) => (
                                <span key={i} className="meta-tag">{g}</span>
                            ))}
                            {data.runtime && data.runtime !== '—' && (
                                <span className="meta-tag">{data.runtime}</span>
                            )}
                            {data.language && (
                                <span className="meta-tag">{data.language}</span>
                            )}
                        </div>

                        {/* Synopsis */}
                        <div className="hero-section">
                            <h3 className="section-label">Synopsis</h3>
                            <p className="hero-synopsis">{data.synopsis}</p>
                        </div>

                        {/* Director & Writer */}
                        <div className="hero-credits-row">
                            {data.director && (
                                <div className="hero-credit">
                                    <span className="credit-label">Director</span>
                                    <span className="credit-value">{data.director}</span>
                                </div>
                            )}
                            {data.writer && (
                                <div className="hero-credit">
                                    <span className="credit-label">Writer</span>
                                    <span className="credit-value">{data.writer}</span>
                                </div>
                            )}
                        </div>

                        {/* Quote */}
                        {data.quote && data.quote !== 'Every story has a beginning.' && (
                            <p className="hero-quote">"{data.quote}"</p>
                        )}
                    </div>
                </div>

                {/* ── Cast Section ─────────────────────────────── */}
                {castDetailed.length > 0 && (
                    <div className="cast-section">
                        <h3 className="section-label">Cast</h3>
                        <div className="cast-grid">
                            {castDetailed.map((member, i) => (
                                <div key={i} className="cast-card">
                                    <div className="cast-photo-wrap">
                                        {member.photo ? (
                                            <img
                                                src={member.photo}
                                                alt={member.name}
                                                className="cast-photo"
                                            />
                                        ) : (
                                            <div className="cast-photo-placeholder">
                                                {member.name.charAt(0)}
                                            </div>
                                        )}
                                    </div>
                                    <p className="cast-name">{member.name}</p>
                                    {member.character && (
                                        <p className="cast-character">{member.character}</p>
                                    )}
                                </div>
                            ))}
                        </div>
                    </div>
                )}

                {/* ── Stills Gallery ──────────────────────────── */}
                {data.stills && data.stills.length > 0 && (
                    <div className="stills-section">
                        <h3 className="section-label">Gallery</h3>
                        <div className="stills-grid">
                            {data.stills.map((img, i) => (
                                <div key={i} className="still-card">
                                    <img src={img} alt={`Scene ${i + 1}`} />
                                </div>
                            ))}
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
}

export default MovieDetails;
